const aiReport = $input.first().json.choices[0].message.content;
const params = $('Set Parameters').first().json;
const model = $input.first().json.model || params.modelName;
const tokens = $input.first().json.usage ? $input.first().json.usage.total_tokens : 'N/A';
const ts = new Date().toISOString();

const html = `<html><body style="margin:0;padding:0;background:#f0f0f0;font-family:Red Hat Display,Arial,sans-serif;"><table width="100%" cellpadding="0" cellspacing="0" style="background:#f0f0f0;"><tr><td align="center" style="padding:24px;"><table width="640" style="max-width:640px;width:100%;"><tr><td style="background:#151515;padding:16px 32px;border-radius:8px 8px 0 0;"><span style="color:#EE0000;font-size:20px;font-weight:700;">Red Hat</span><span style="float:right;color:#C6C6C6;font-size:12px;line-height:28px;">OpenShift Developer Sandbox</span></td></tr><tr><td style="background:#DC382D;padding:28px 32px;"><h1 style="margin:0;font-size:24px;color:#FFF;">Deployment Monitor Report</h1><p style="margin:6px 0 0;font-size:14px;color:rgba(255,255,255,.85);">MCP Tool: monitorDeployments | Model: ${model}</p></td></tr><tr><td style="background:#292929;padding:0;"><table width="100%"><tr><td style="padding:12px 16px;text-align:center;color:#A3A3A3;font-size:11px;border-right:1px solid #3C3C3C;width:25%;"><b style="display:block;color:#FFF;font-size:13px;">${params.namespace}</b>Namespace</td><td style="padding:12px 16px;text-align:center;color:#A3A3A3;font-size:11px;border-right:1px solid #3C3C3C;width:25%;"><b style="display:block;color:#FFF;font-size:13px;">${ts}</b>Generated</td><td style="padding:12px 16px;text-align:center;color:#A3A3A3;font-size:11px;border-right:1px solid #3C3C3C;width:25%;"><b style="display:block;color:#FFF;font-size:13px;">${model}</b>AI Model</td><td style="padding:12px 16px;text-align:center;color:#A3A3A3;font-size:11px;width:25%;"><b style="display:block;color:#FFF;font-size:13px;">${tokens}</b>Tokens</td></tr></table></td></tr><tr><td style="background:#FFF;padding:28px 32px;"><h2 style="margin:0 0 16px;font-size:17px;border-bottom:2px solid #DC382D;padding-bottom:10px;">AI Analysis Report</h2><p style="font-size:11px;color:#6A6E73;margin:0 0 16px;">Pipeline: MCP Server (monitorDeployments) → AI Analysis → Mailpit</p>${aiReport}</td></tr><tr><td style="background:#F5F5F5;padding:16px 32px;border-top:1px solid #E0E0E0;text-align:center;"><span style="display:inline-block;background:#EE0000;color:white;font-size:10px;font-weight:700;padding:4px 10px;border-radius:3px;">RED HAT</span> <span style="font-size:11px;color:#6A6E73;margin:0 8px;">OpenShift MCP</span> <span style="font-size:11px;color:#DC382D;font-weight:600;margin:0 8px;">${model}</span> <span style="font-size:11px;color:#6A6E73;margin:0 8px;">n8n</span></td></tr><tr><td style="background:#151515;padding:20px 32px;border-radius:0 0 8px 8px;text-align:center;"><p style="margin:0;font-size:12px;color:#A3A3A3;">Auto-generated by n8n on <b style="color:#FFF;">Red Hat OpenShift Developer Sandbox</b></p></td></tr></table></td></tr></table></body></html>`;

return [{
  json: {
    html,
    subject: `[Red Hat OpenShift] Deployment Monitor Report | ${params.namespace} | ${ts}`,
    destinationEmail: params.destinationEmail,
    namespace: params.namespace,
    timestamp: ts
  }
}];
